python3 << 'EOF'
import json
d=json.load(open('/tmp/iso.json'))
def file_of(n):
    short=n.split('.')[-1]
    for f in ['AlgebraicJacobian/Picard/TensorObjSubstrate.lean',
              'AlgebraicJacobian/Picard/TensorObjSubstrate/DualInverse.lean',
              'AlgebraicJacobian/Picard/TensorObjSubstrate/PresheafInternalHom.lean']:
        import subprocess
        r=subprocess.run(['grep','-nE',r'(def|lemma|theorem|instance|abbrev|structure)\s+'+short.replace('₂',r'₂')+r'\b',f],capture_output=True,text=True)
        if r.stdout.strip():
            return f
    return '??'
groups={'TOS':[], 'DUAL':[], 'PIH':[]}
inf={'sheafificationCompPullback_comp_tail','sliceDualTransportInv'}
for x in d:
    n=x['lean_name']; f=file_of(n)
    tag = 'TOS' if 'TensorObjSubstrate.lean' in f else ('DUAL' if 'DualInverse' in f else ('PIH' if 'PresheafInternalHom' in f else '??'))
    groups.setdefault(tag,[]).append((n, '∞' if n.split('.')[-1] in inf else ''))
for k,v in groups.items():
    print(f"=== {k} ({len(v)}) ===")
    for n,m in v: print(f"  {m:1} {n}")
EOF
